18	function rowToDashboard(row: DashboardRow): Dashboard {
19	  return {
20	    id: row.id,
21	    uid: row.uid,
22	    title: row.title,
23	    ...(row.description !== null ? {description: row.description} : {}),
24	    tags: JSON.parse(row.tags) as string[],
25	    panels: JSON.parse(row.panels_json) as Dashboard["panels"],
26	    variables: JSON.parse(row.variables_json) as Dashboard["variables"],
27	    timeRange: JSON.parse(row.time_range_json) as Dashboard["timeRange"],
28	    ...(row.refresh_interval !== null ? {refreshInterval: row.refresh_interval} : {}),
29	    version: row.version,
30	    updatedAt: row.updated_at,
31	    createdAt: row.created_at,
32	  };
33	}
