53	export class InMemoryDashboardStorage implements DashboardStorage {
54	  private store = new Map<string, Dashboard>();
55	
56	  async list(): Promise<DashboardSummary[]> {
57	    return Array.from(this.store.values()).map((d) => ({
58	      id: d.id,
59	      uid: d.uid,
60	      title: d.title,
61	      tags: d.tags,
62	      updatedAt: d.updatedAt,
63	    }));
