86	export class MySQLDashboardStorage implements DashboardStorage {
87	  private getConnection;
88	
89	  constructor(getConnection: () => Promise<import("mysql2/promise").Connection>) {
90	    this.getConnection = getConnection;
91	  }
92	
93	  async list(): Promise<DashboardSummary[]> {
94	    const conn = await this.getConnection();
95	    try {
96	      const [rows] = await conn.query("SELECT id, uid, title, tags, updated_at, created_at FROM dashboards ORDER BY updated_at DESC");
97	      return (rows as DashboardRow[]).map(rowToSummary);
98	    } finally {
99	      await conn.end();
100	    }
101	  }
102	
103	  async get(uid: string): Promise<Dashboard | null> {
104	    const conn = await this.getConnection();
105	    try {
106	      const [rows] = await conn.query("SELECT * FROM dashboards WHERE uid = ?", [uid]);
107	      const row = (rows as DashboardRow[])[0];
108	      if (!row) return null;
109	      return rowToDashboard(row);
110	    } finally {
111	      await conn.end();
112	    }
113	  }
114	
115	  async create(dashboard: Dashboard): Promise<Dashboard> {
116	    const conn = await this.getConnection();
117	    try {
118	      await conn.query(
119	        `INSERT INTO dashboards (id, uid, title, description, tags, panels_json, variables_json, time_range_json, refresh_interval, version, updated_at, created_at)
120	         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`,
121	        [
122	          dashboard.id,
123	          dashboard.uid,
124	          dashboard.title,
125	          dashboard.description ?? null,
126	          JSON.stringify(dashboard.tags),
127	          JSON.stringify(dashboard.panels),
128	          JSON.stringify(dashboard.variables),
129	          JSON.stringify(dashboard.timeRange),
130	          dashboard.refreshInterval ?? null,
131	          dashboard.version,
132	          dashboard.updatedAt,
133	          dashboard.createdAt,
134	        ],
135	      );
136	      return dashboard;
137	    } finally {
138	      await conn.end();
139	    }
140	  }
141	
142	  async update(uid: string, dashboard: Dashboard): Promise<Dashboard | null> {
143	    const conn = await this.getConnection();
144	    try {
145	      const [result] = await conn.query(
146	        `UPDATE dashboards SET title = ?, description = ?, tags = ?, panels_json = ?, variables_json = ?, time_range_json = ?, refresh_interval = ?, version = ?, updated_at = ?
147	         WHERE uid = ? AND version = ?`,
148	        [
149	          dashboard.title,
150	          dashboard.description ?? null,
151	          JSON.stringify(dashboard.tags),
152	          JSON.stringify(dashboard.panels),
153	          JSON.stringify(dashboard.variables),
154	          JSON.stringify(dashboard.timeRange),
155	          dashboard.refreshInterval ?? null,
156	          dashboard.version,
157	          dashboard.updatedAt,
158	          uid,
159	          dashboard.version - 1,
160	        ],
161	      );
162	      const affected = (result as {affectedRows: number}).affectedRows;
163	      if (affected === 0) return null;
164	      return dashboard;
165	    } finally {
166	      await conn.end();
167	    }
168	  }
169	
170	  async delete(uid: string): Promise<boolean> {
171	    const conn = await this.getConnection();
172	    try {
173	      const [result] = await conn.query("DELETE FROM dashboards WHERE uid = ?", [uid]);
174	      return (result as {affectedRows: number}).affectedRows > 0;
175	    } finally {
176	      await conn.end();
177	    }
178	  }
179	}
