66	    const {uid} = c.req.param();
67	    const existing = await storage.get(uid);
68	    if (!existing) {
69	      return c.json({error: "Dashboard not found"}, 404);
70	    }
71	    const body = c.req.valid("json") as UpdateDashboardRequest;
72	
73	    // Optimistic concurrency check
74	    if (body.version !== existing.version) {
75	      return c.json({error: "Version conflict", currentVersion: existing.version}, 409);
76	    }
77	
78	    const updated: Dashboard = {
79	      ...existing,
80	      title: body.title ?? existing.title,
81	      tags: body.tags ?? existing.tags,
82	      variables: body.variables ?? existing.variables,
83	      timeRange: body.timeRange ?? existing.timeRange,
84	      panels: body.panels ?? existing.panels,
85	      version: existing.version + 1,
86	      updatedAt: toMySQLDatetime(),
