7	const BYTES_PER_KB = 1024;
8	const BYTES_PER_MB = BYTES_PER_KB * BYTES_PER_KB;
9	const MAX_BODY_SIZE = BYTES_PER_MB;
10	const MAX_RESPONSE_SIZE = 50 * BYTES_PER_MB;
11	const CLP_HEADER_PREFIX = "x-clp-";
12	const GATEWAY_HEADER = "x-clp-gateway";
13	const HTTP_FORBIDDEN = 403;
14	const HTTP_RATE_LIMITED = 429;
15	const HTTP_PAYLOAD_TOO_LARGE = 413;
16	const HTTP_REQUEST_TIMEOUT = 408;
17	const RATE_LIMIT_WINDOW_MS = 60_000;
18	const RATE_LIMIT_MAX_HITS = 100;
19	const SERVER_REQUEST_TIMEOUT_MS = 120_000;
20	const MS_PER_SECOND = 1000;
21	
22	type Role = "viewer" | "editor" | "admin";
23	
24	const ROLE_HIERARCHY: Record<Role, number> = {admin: 2, editor: 1, viewer: 0};
25	
26	const WRITE_METHODS = new Set(["POST",
27	    "PUT",
28	    "PATCH",
29	    "DELETE"]);
30	
31	/**
32	 *
33	 */
34	function isProduction (): boolean {
35	    // eslint-disable-next-line dot-notation
36	    return "production" === process.env["NODE_ENV"];
37	}
