39	/**
40	 *
41	 * @param c
42	 * @param c.req
43	 * @param c.req.header
44	 */
45	function getRole (c: {req: {header: (name: string) => string | undefined}}): Role {
46	    const roleHeader = c.req.header("x-clp-role")?.toLowerCase();
47	    if (roleHeader && roleHeader in ROLE_HIERARCHY) {
48	        return roleHeader as Role;
49	    }
50	
51	    return "viewer";
52	}
53	
54	/**
55	 *
56	 * @param userRole
57	 * @param requiredRole
58	 */
59	function hasRole (userRole: Role, requiredRole: Role): boolean {
60	    return ROLE_HIERARCHY[userRole] >= ROLE_HIERARCHY[requiredRole];
61	}
