import {toMySQLDatetime} from "./datetime-utils.js";

export interface SchemaRecord {
  id: string;
  name: string;
  content: string;
  createdAt: string;
  updatedAt: string;
}

export interface SchemaStorage {
  list(): Promise<SchemaRecord[]>;
  get(id: string): Promise<SchemaRecord | null>;
  create(schema: SchemaRecord): Promise<void>;
  update(id: string, schema: Partial<SchemaRecord>): Promise<SchemaRecord | null>;
  delete(id: string): Promise<boolean>;
}

export class InMemorySchemaStorage implements SchemaStorage {
  private store = new Map<string, SchemaRecord>();

  async list(): Promise<SchemaRecord[]> {
    return Array.from(this.store.values());
  }

  async get(id: string): Promise<SchemaRecord | null> {
    return this.store.get(id) ?? null;
  }

  async create(schema: SchemaRecord): Promise<void> {
    this.store.set(schema.id, schema);
  }

  async update(id: string, schema: Partial<SchemaRecord>): Promise<SchemaRecord | null> {
    const existing = this.store.get(id);
    if (!existing) return null;
    const updated: SchemaRecord = {...existing, ...schema, updatedAt: toMySQLDatetime()};
    this.store.set(id, updated);
    return updated;
  }

  async delete(id: string): Promise<boolean> {
    return this.store.delete(id);
  }
}

import {Hono} from "hono";
import type {TSchema} from "@sinclair/typebox";
import {tbValidator} from "@hono/typebox-validator";
import {Type} from "@sinclair/typebox";
import {nanoid} from "nanoid";
import type {SchemaStorage} from "../storage/schema-storage.js";
import {InMemorySchemaStorage} from "../storage/schema-storage.js";
import {toMySQLDatetime} from "../storage/datetime-utils.js";

let storage: SchemaStorage = new InMemorySchemaStorage();

export function setSchemaStorage(s: SchemaStorage): void {
  storage = s;
}

const CreateSchemaSchema = Type.Object({
  name: Type.String({minLength: 1}),
  content: Type.String({minLength: 1}),
});

const UpdateSchemaSchema = Type.Partial(
  Type.Object({
    name: Type.String({minLength: 1}),
    content: Type.String({minLength: 1}),
  }),
);

const ValidateSchemaSchema = Type.Object({
  content: Type.String({minLength: 1}),
});

export const schemaRoutes = new Hono()
  .get("/", async (c): Promise<Response> => {
    const schemas = await storage.list();
    return c.json(schemas);
  })
  .post("/", tbValidator("json", CreateSchemaSchema as unknown as TSchema), async (c) => {
    const body = c.req.valid("json") as {name: string; content: string};
    const now = toMySQLDatetime();
    const schema = {
      id: nanoid(10),
      name: body.name,
      content: body.content,
      createdAt: now,
      updatedAt: now,
    };
    await storage.create(schema);
    return c.json(schema, 201);
  })
  .get("/:id", async (c) => {
    const {id} = c.req.param();
    const schema = await storage.get(id);
    if (!schema) {
      return c.json({error: "Schema not found"}, 404);
    }
    return c.json(schema);
  })
  .put("/:id", tbValidator("json", UpdateSchemaSchema as unknown as TSchema), async (c) => {
    const {id} = c.req.param();
    const existing = await storage.get(id);
    if (!existing) {
      return c.json({error: "Schema not found"}, 404);
    }
    const body = c.req.valid("json") as {name?: string; content?: string};
    const result = await storage.update(id, {
      ...(body.name !== undefined ? {name: body.name} : {}),
      ...(body.content !== undefined ? {content: body.content} : {}),
    });
    return c.json(result);
  })
  .delete("/:id", async (c) => {
    const {id} = c.req.param();
    const deleted = await storage.delete(id);
    if (!deleted) {
      return c.json({error: "Schema not found"}, 404);
    }
    return c.json({success: true}, 200);
  })
  .post("/validate", tbValidator("json", ValidateSchemaSchema as unknown as TSchema), async (c) => {
    const body = c.req.valid("json") as {content: string};
    const errors: string[] = [];
    const content = body.content.trim();
    if (content.length === 0) {
      errors.push("Schema content must not be empty");
    }
    try {
      JSON.parse(content);
    } catch {
      errors.push("Schema content is not valid JSON");
    }
    if (errors.length > 0) {
      return c.json({valid: false, errors});
    }
    return c.json({valid: true});
  });

export type SchemaRoutesType = typeof schemaRoutes;

